class VirtualBlockTable:
    def __init__(self):
        self.table = {}
    def allocate_page(self, logical_idx, physical_idx):
        self.table[logical_idx] = physical_idx
    def get_physical(self, logical_idx):
        return self.table.get(logical_idx, -1)

def run_practice():
    pt = VirtualBlockTable()
    pt.allocate_page(10, 1024)
    assert pt.get_physical(10) == 1024
    assert pt.get_physical(20) == -1
    print('[PASS] PagedAttention virtual translations validated.')

if __name__ == '__main__':
    run_practice()
